VALUES
  ('social-worker-moex-03270', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Hoffman（1987）提出同理的四個層次，「能分辨自己和別人感受，但未能理解別人感受，以為別 人內心感覺和自己一樣」，這是那一個層次的同理？', '["整體的同理（globalempathy）", "自我中心的同理（egocentricempathy）", "對他人情感的同理（empathyforanother’sfeelings）", "對他人生活情況的同理（empathyforanother’slifecondition）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:17+00:00", "source_pdf_sha1": "a087d56213ab", "answer_pdf_sha1": "daeec4fbf76e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03271', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列何者不是Sternberg（1986）的愛情三角理論（triangulartheoryoflove）中所指的愛情三元素？', '["親密（intimacy）", "激情（passion）", "承諾（commitment）", "情感（emotion）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:17+00:00", "source_pdf_sha1": "a087d56213ab", "answer_pdf_sha1": "daeec4fbf76e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03272', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '遊戲是兒童早期學習的主要媒介，透過遊戲可以增進與同儕關係、社會接觸或社交技巧，下列何 者錯誤？', '["Piaget（1967）認為遊戲可以操練和強化兒童認知技巧", "Vygotsky（1962）強調想像性遊戲有助於兒童象徵思考的發展", "Berlyne（1960）認為遊戲滿足兒童探索、好奇心和驚奇等發展需要", "Pellegrini（2022）討論母親跟孩子玩比較激烈和翻滾的遊戲所具有的價值與可發揮的功能"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:17+00:00", "source_pdf_sha1": "a087d56213ab", "answer_pdf_sha1": "daeec4fbf76e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03273', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '當人們退休時保有工作的滿意度與幸福感，就更容易適應新的生活型態。此說法最符合下列那一 個退休適應相關理論觀點？', '["活動理論（activitytheory）", "持續理論（continuitytheory）", "撤退理論（disengagementtheory）", "自我統整理論（theoryofegointegrity）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:17+00:00", "source_pdf_sha1": "a087d56213ab", "answer_pdf_sha1": "daeec4fbf76e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03274', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '對於成年中期的發展任務與生理、心理、社會的描述，下列那一個最不符合？', '["屬於Erikson心理發展理論的生產與停滯的衝突", "開始探究變老的意義，檢視之前的選擇是否令人滿意", "男性也會經歷更年期，開始評價自己的職涯、家庭關係或人生重大決定", "依據Levinson的成年發展理論，任務是建立成人的身分認同，決定成年期目標"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:17+00:00", "source_pdf_sha1": "a087d56213ab", "answer_pdf_sha1": "daeec4fbf76e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03275', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '50歲的甲在子女都大學畢業之後，決定再次進入職場，不再過著依賴別人、取悅長輩、只聽配偶 或伴侶意見的生活，想要重新定位角色、發揮自己的價值。這樣的敘述最符合下列那項概念？', '["中年的角色模糊", "中年的角色衝突", "中年的角色負荷", "中年的重新建構"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:17+00:00", "source_pdf_sha1": "a087d56213ab", "answer_pdf_sha1": "daeec4fbf76e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03276', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '中年人常常必須擔負雙重的角色：養育子女、照顧長輩，也被認為是「三明治世代（sandwich generation）」，關於此角色的敘述，下列何者錯誤？', '["只是人生的一個階段或單一事件", "因為醫療的進步，慢性病逐漸取代急性病，因此照顧的時間也更增加", "照顧者較高比例為女性，因此對其生活影響尤大", "全職照顧者可能會有被家人和朋友拋棄的感覺和焦慮等壓力感受"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:17+00:00", "source_pdf_sha1": "a087d56213ab", "answer_pdf_sha1": "daeec4fbf76e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03277', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '寬恕為個人在心理與人際關係產生的益處，將促使人出現新的自我。寬恕的歷程包括那四個階段？', '["找出憤怒→決定寬恕→盡力寬恕→發現與釋放", "找出憤怒→發現與釋放→決定寬恕→盡力寬恕", "發現與釋放→決定寬恕→找出憤怒→盡力寬恕", "決定寬恕→找出憤怒→盡力寬恕→發現與釋放"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:17+00:00", "source_pdf_sha1": "a087d56213ab", "answer_pdf_sha1": "daeec4fbf76e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03278', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關隔代教養對照顧者產生的影響，下列何者錯誤？', '["照顧者可能與不需照顧孫子女同儕朋友產生疏離，進而失去支持網絡", "照顧者常會擔心自己是否能活得夠久，否則孫子女就沒有人可以照顧", "照顧者親職取代即將退休或已退休產生的失落，並強化跨世代影響力", "隔代教養有較高比例發生兒童疏忽與虐待的風險"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:17+00:00", "source_pdf_sha1": "a087d56213ab", "answer_pdf_sha1": "daeec4fbf76e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03279', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關中年人身心狀況的敘述，下列何者錯誤？', '["糖尿病、心臟疾病、高血壓是中年期常見的慢性疾病", "停經過早的女性容易罹患心臟病、骨質疏鬆症，以及其他慢性疾病", "臺灣30歲以上女性最大的癌症隱憂是子宮頸癌", "不論何種性別，人都會面臨更年期"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:17+00:00", "source_pdf_sha1": "a087d56213ab", "answer_pdf_sha1": "daeec4fbf76e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
